#!/usr/bin/env python3
import os, base64, re as _re

files = [
  ('lib\\\\constants\\\\colors.ts', ''),
  ('app\\\\dashboard\\\\page.tsx', ''),
  ('app\\\\tracker\\\\page.tsx', ''),
  ('app\\\\staff\\\\page.tsx', ''),
  ('app\\\\covers\\\\page.tsx', ''),
  ('app\\\\departments\\\\page.tsx', ''),
  ('app\\\\forecast\\\\page.tsx', ''),
  ('app\\\\budget\\\\page.tsx', ''),
  ('app\\\\invoices\\\\page.tsx', ''),
]

for win_path, b64 in files:
    path = win_path.replace("\\\\", os.sep).replace("\\", os.sep)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "wb") as f:
        f.write(content.encode("utf-8"))
    print(f"Written: {path}")
print("\nDone.")
print("Now run: git add . && git commit -m \"UX consistency: shared colours, dept colours, uniform card radius\" && vercel --prod")
